mapper.insert:
INSERT INTO tasting_note_metric     /* 맛 프로파일 테이블 */
(
    note_id         /* 테이스팅 노트 키 */
  , metric_code     /* 맛 프로파일 코드 키 */
  , score           /* 점수 */
)
VALUES
(
    #{noteId}
  , #{metricCode}
  , #{score}
)

mapper.delete:
DELETE
  FROM tasting_note_metric      /* 맛 프로파일 테이블 */
 WHERE note_id = #{noteId}
